   207→  query: string,
   208→  numResults: number,
   209→  manifest: Manifest
   210→): Promise<FileSearchResult[]> {
   211→  try {
   212→    logger.info('[Legacy File Search] Using legacy file parts mode');
   213→
   214→    const ai = new GoogleGenAI({ apiKey });
   215→
   216→    // Webコンテンツのみを使用
   217→    const searchableFiles = manifest.files.filter((f: ManifestFile) =>
   218→      f.source_type === 'web'
   219→    );
   220→
   221→    logger.info({
   222→      count: searchableFiles.length,
   223→      files: searchableFiles.map(f => ({ id: f.file_id, name: f.display_name }))
