   231→    // ファイルパーツを構築
   232→    const fileParts = searchableFiles.map((file: ManifestFile) => ({
   233→      fileData: {
   234→        mimeType: 'text/plain',
   235→        fileUri: `https://generativelanguage.googleapis.com/v1beta/${file.file_id}`
   236→      }
   237→    }));
   238→
   239→    const availableCategories = Array.from(new Set(
   240→      searchableFiles
   241→        .map((f: ManifestFile) => f.category)
   242→        .filter((c): c is string => !!c)
   243→    ));
