   274→    // generateContent with file parts
   275→    const response = await ai.models.generateContent({
   276→      model: getGenerativeModelId(),
   277→      contents: [
   278→        { text: searchPrompt },
   279→        ...fileParts
   280→      ],
   281→      config: {
   282→        temperature: 0.1
   283→      }
