   301→/**
   302→ * 環境に応じたmanifestを取得（静的インポート使用、Edge Runtime対応）
   303→ */
   304→async function loadManifest(): Promise<Manifest> {
   305→  try {
   306→    const envQaIds = process.env.FILESTORE_QA_IDS
   307→      ? process.env.FILESTORE_QA_IDS.split(',').map(id => id.trim()).filter(Boolean)
   308→      : undefined;
   309→
   310→    // 環境変数でFile Search Store名を上書き可能
   311→    // 本番/検証/開発環境で異なるStoreを使用する場合に設定
   312→    const envStoreName = process.env.FILE_SEARCH_STORE_NAME || '';
   313→
   314→    // 環境に応じたmanifestを選択（静的インポートを使用）
   315→    const isStaging = envStoreName.includes('staging');
   316→    const baseManifest: Manifest = isStaging
   317→      ? (manifestStagingJson as Manifest)
   318→      : (manifestJson as Manifest);
   319→
   320→    // デバッグ: 実際のmanifest内容を出力
   321→    logger.info({
   322→      isStaging,
   323→      envStoreName,
   324→      manifestFiles: baseManifest.files?.length || 0,
   325→      fileIds: baseManifest.files?.map(f => f.file_id),
   326→      storeName: baseManifest.file_search_store_name
   327→    }, '[Manifest] Loading manifest (static import)');
   328→
   329→    // File Search Store名の決定（環境変数優先）
   330→    const fileSearchStoreName = envStoreName || baseManifest.file_search_store_name;
   331→
   332→    if (envStoreName) {
   333→      logger.info({ envStoreName }, '[Manifest] Using FILE_SEARCH_STORE_NAME from environment');
   334→    }
   335→
   336→    if (!envQaIds || envQaIds.length === 0) {
   337→      return {
   338→        ...baseManifest,
   339→        file_search_store_name: fileSearchStoreName
   340→      };
   341→    }
   342→
   343→    const filteredFiles = baseManifest.files.filter(
   344→      f => envQaIds.includes(f.file_id)
   345→    );
   346→
   347→    return {
   348→      ...baseManifest,
   349→      file_search_store_name: fileSearchStoreName,
   350→      files: filteredFiles
   351→    };
   352→  } catch (error) {
   353→    logger.error({ error }, 'Failed to load manifest');
   354→    return { version: '1.0.0', updated_at: '', files: [] };
   355→  }
   356→}
   357→
   358→/**
   359→ * 検索結果をパース
   360→ */
   361→function parseSearchResults(responseText: string, manifest: Manifest): FileSearchResult[] {
   362→  try {
   363→    let cleanText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '');
   364→    const jsonMatch = cleanText.match(/\[[\s\S]*\]/);
   365→    if (!jsonMatch) {
   366→      logger.warn('No JSON array found in response');
   367→      return [];
   368→    }
   369→
   370→    const results = JSON.parse(jsonMatch[0]);
   371→    if (!Array.isArray(results)) {
   372→      return [];
   373→    }
   374→
   375→    // カテゴリーからURLへのマッピング
   376→    const categoryToUrl: Map<string, string> = new Map();
   377→    manifest.files.forEach((file: ManifestFile) => {
   378→      if (file.category && file.url) {
   379→        categoryToUrl.set(file.category, file.url);
   380→      }
   381→    });
   382→
   383→    return results.map((r: any) => {
   384→      const category = r.category || (r.source_type === 'web' ? 'トップページ' : 'Q&A');
   385→      const url = categoryToUrl.get(category) || 'https://wmg2027.jp/';
   386→
   387→      return {
   388→        text: r.answer || '',
   389→        original_question: r.original_question || r.question || '',
   390→        display_name: r.source_type === 'web' ? '公式サイト' : 'Q&Aデータ',
   391→        uri: url,
   392→        source_type: (r.source_type as 'qa' | 'web') || 'qa',
   393→        category: category,
   394→        locale: 'ja',
   395→        relevance: r.relevance as 'high' | 'medium' | 'low' | undefined
   396→      };
   397→    });
   398→  } catch (error) {
   399→    logger.error({ error }, 'Failed to parse search results');
   400→    return [];
   401→  }
   402→}
   403→
   404→/**
   405→ * フォールバックコンテキスト
   406→ */
   407→function getFallbackContext(): FileSearchResult[] {
   408→  return [
   409→    {
   410→      text: 'この質問に関する具体的な情報は見つかりませんでした。ワールドマスターズゲームズ2027に関する詳細情報は、公式サイトをご確認ください。',
   411→      display_name: '公式サイト案内',
   412→      uri: 'https://wmg2027.jp/',
   413→      source_type: 'web',
   414→      locale: 'ja'
   415→    }
   416→  ];
   417→}
   418→
   419→/**
   420→ * Gemini APIキーを取得
   421→ */
   422→function getGeminiApiKey(): string | undefined {
   423→  return process.env.GEMINI_API_KEY || process.env.GOOGLE_GENERATIVE_AI_API_KEY;
   424→}
   425→
   426→/**
   427→ * モデルIDを取得
   428→ */
   429→function getGenerativeModelId(): string {
   430→  const envId = process.env.GEMINI_MODEL_ID;
   431→  if (envId) {
   432→    return envId.replace(/^models\//, '');
   433→  }
   434→  return 'gemini-2.5-flash';
   435→}
