/**
 * Gemini File Search Store Service
 * 新SDK(@google/genai)を使用したFile Search Store実装
 *
 * Migration:
 * - 旧: @google/generative-ai - 48時間で削除されるFile API
 * - 新: @google/genai - 永続化されたFile Search Store + fileSearch tool
 *
 * Note: This is a server-only module
 */

// import 'server-only'; // Commented for unit testing
import { GoogleGenAI } from '@google/genai';
import type { FileSearchResult, FileSearchResponse } from '@/types/gemini';
import { logger } from '@/server/lib/logger';
// 両方のmanifestを静的インポート（Edge Runtime対応）
import manifestJson from '@/../data/file-store-manifest.json' assert { type: 'json' };
import manifestStagingJson from '@/../data/file-store-manifest-staging.json' assert { type: 'json' };

interface SearchOptions {
  timeout?: number;
  numResults?: number;
}

interface ManifestFile {
  file_id: string;
  file_search_store_name?: string;
  display_name: string;
  source_type: 'qa' | 'web';
  uploaded_at: string;
  locale?: string;
  category?: string;
  url?: string;
}

interface Manifest {
  version: string;
  updated_at: string;
  file_search_store_name?: string;
  files: ManifestFile[];
}

/**
 * Gemini File Search APIを呼び出してTop3件のコンテキストを取得
 */
export async function searchFiles(
  query: string,
  options: SearchOptions = {}
): Promise<FileSearchResponse> {
  logger.info({ query }, '[File Search] Starting search');

  const { timeout = 30000, numResults = 3 } = options;

  try {
    const apiKey = getGeminiApiKey();
    if (!apiKey) {
      logger.error('[File Search] Gemini API key is not set');
      return {
        success: true,
        results: getFallbackContext()
      };
    }

    // manifestを取得
    const manifest = await loadManifest();

    // タイムアウト処理
    const searchPromise = performFileSearchStoreSearch(apiKey, query, numResults, manifest);
    const timeoutPromise = new Promise<FileSearchResult[]>((_, reject) =>
      setTimeout(() => reject(new Error('Search timeout')), timeout)
    );

    const results = await Promise.race([searchPromise, timeoutPromise]);

    return {
      success: true,
      results: results.length > 0 ? results : getFallbackContext()
    };
  } catch (error) {
    logger.error({ error }, 'File Search error');
    return {
      success: true,
      results: getFallbackContext()
    };
  }
}

/**
 * File Search Store APIを使用した検索（新SDK）
 */
async function performFileSearchStoreSearch(
  apiKey: string,
  query: string,
  numResults: number,
  manifest: Manifest
): Promise<FileSearchResult[]> {
  try {
    logger.info({
      totalFiles: manifest.files.length,
      version: manifest.version,
      fileSearchStoreName: manifest.file_search_store_name
    }, '[File Search Store] Manifest loaded');

    // File Search Store名がない場合はレガシーモードにフォールバック
    if (!manifest.file_search_store_name) {
      logger.warn('[File Search Store] No file_search_store_name in manifest, using legacy mode');
      return performLegacySearch(apiKey, query, numResults, manifest);
    }

    // 新SDKでクライアント作成
    const ai = new GoogleGenAI({ apiKey });

    // カテゴリーリストを抽出
    const availableCategories = Array.from(new Set(
      manifest.files
        .map((f: ManifestFile) => f.category)
        .filter((c): c is string => !!c)
    ));

    logger.info({ availableCategories }, '[File Search Store] Available categories');

    // File Search Toolを使用してコンテンツ生成
    // 注意: RECITATIONエラーを避けるため、要約・言い換えを明示的に指示
    const searchPrompt = `あなたはWMG2027の情報検索アシスタントです。

## タスク
ユーザーの質問に関連する情報をFile Search Storeから検索し、**要約して**回答してください。
直接引用ではなく、情報を**自分の言葉で言い換えて**説明してください。

## ユーザーの質問
${query}

## 検索対象カテゴリー
${availableCategories.map(c => `- ${c}`).join('\n')}

## 出力形式
関連情報を最大${numResults}件、以下のJSON形式で出力：
[
  {
    "original_question": "関連するトピック名",
    "answer": "要約した説明（自分の言葉で）",
    "relevance": "high" | "medium" | "low",
    "source_type": "qa" | "web",
    "category": "カテゴリー名"
  }
]

情報が見つからない場合は [] を返してください。`;

    logger.info('[File Search Store] Calling Gemini API with fileSearch tool');

    // generateContent with fileSearch tool（新SDK）
    const response = await ai.models.generateContent({
      model: getGenerativeModelId(),
      contents: searchPrompt,
      config: {
        tools: [{
          fileSearch: {
            fileSearchStoreNames: [manifest.file_search_store_name]
          }
        }],
        temperature: 0.1
      }
    });

    // デバッグ: 完全なレスポンス構造を出力
    logger.info({
      responseKeys: Object.keys(response),
      candidates: response.candidates?.length,
      fullResponse: JSON.stringify(response).substring(0, 1000)
    }, '[File Search Store] Full API response');

    const text = response.text || '';

    logger.info({
      textLength: text.length,
      preview: text.substring(0, 200)
    }, '[File Search Store] Gemini API response');

    // Grounding metadataをログ出力
    if (response.candidates?.[0]?.groundingMetadata) {
      logger.info({
        groundingMetadata: response.candidates[0].groundingMetadata
      }, '[File Search Store] Grounding metadata');
    }

    // レスポンスをパース
    const results = parseSearchResults(text, manifest);
    logger.info({
      count: results.length,
      results: results.map(r => ({ question: r.original_question?.substring(0, 50), type: r.source_type }))
    }, '[File Search Store] Parsed results');

    return results.slice(0, numResults);
  } catch (error) {
    logger.error({ error }, '[File Search Store] Search error');
    // エラー時はレガシーモードにフォールバック
    return performLegacySearch(apiKey, query, numResults, manifest);
  }
}

/**
 * レガシーFile API検索（フォールバック用）
 */
async function performLegacySearch(
  apiKey: string,
  query: string,
  numResults: number,
  manifest: Manifest
): Promise<FileSearchResult[]> {
  try {
    logger.info('[Legacy File Search] Using legacy file parts mode');

    const ai = new GoogleGenAI({ apiKey });

    // Webコンテンツのみを使用
    const searchableFiles = manifest.files.filter((f: ManifestFile) =>
      f.source_type === 'web'
    );

    logger.info({
      count: searchableFiles.length,
      files: searchableFiles.map(f => ({ id: f.file_id, name: f.display_name }))
    }, '[Legacy File Search] Searchable files');

    if (searchableFiles.length === 0) {
      logger.warn('[Legacy File Search] No searchable files found');
      return [];
    }

    // ファイルパーツを構築
    const fileParts = searchableFiles.map((file: ManifestFile) => ({
      fileData: {
        mimeType: 'text/plain',
        fileUri: `https://generativelanguage.googleapis.com/v1beta/${file.file_id}`
      }
    }));

    const availableCategories = Array.from(new Set(
      searchableFiles
        .map((f: ManifestFile) => f.category)
        .filter((c): c is string => !!c)
    ));

    // 注意: RECITATIONエラーを避けるため、要約・言い換えを明示的に指示
    const searchPrompt = `あなたはWMG2027の情報検索アシスタントです。

## タスク
ユーザーの質問に関連する情報を検索し、**要約して**回答してください。
直接引用ではなく、情報を**自分の言葉で言い換えて**説明してください。

## ユーザーの質問
${query}

## 検索対象カテゴリー
${availableCategories.map(c => `- ${c}`).join('\n')}

## 出力形式
関連情報を最大${numResults}件、以下のJSON形式で出力：
[
  {
    "original_question": "関連するトピック名",
    "answer": "要約した説明（自分の言葉で）",
    "relevance": "high" | "medium" | "low",
    "source_type": "qa" | "web",
    "category": "カテゴリー名"
  }
]

情報が見つからない場合は [] を返してください。`;

    logger.info('[Legacy File Search] Calling Gemini API');

    // generateContent with file parts
    const response = await ai.models.generateContent({
      model: getGenerativeModelId(),
      contents: [
        { text: searchPrompt },
        ...fileParts
      ],
      config: {
        temperature: 0.1
      }
    });

    const text = response.text || '';

    logger.info({
      textLength: text.length,
      preview: text.substring(0, 200)
    }, '[Legacy File Search] Response');

    const results = parseSearchResults(text, manifest);
    return results.slice(0, numResults);
  } catch (error) {
    logger.error({ error }, '[Legacy File Search] Error');
    return [];
  }
}

/**
 * 環境に応じたmanifestを取得（静的インポート使用、Edge Runtime対応）
 */
async function loadManifest(): Promise<Manifest> {
  try {
    const envQaIds = process.env.FILESTORE_QA_IDS
      ? process.env.FILESTORE_QA_IDS.split(',').map(id => id.trim()).filter(Boolean)
      : undefined;

    // 環境変数でFile Search Store名を上書き可能
    // 本番/検証/開発環境で異なるStoreを使用する場合に設定
    const envStoreName = process.env.FILE_SEARCH_STORE_NAME || '';

    // 環境に応じたmanifestを選択（静的インポートを使用）
    const isStaging = envStoreName.includes('staging');
    const baseManifest: Manifest = isStaging
      ? (manifestStagingJson as Manifest)
      : (manifestJson as Manifest);

    // デバッグ: 実際のmanifest内容を出力
    logger.info({
      isStaging,
      envStoreName,
      manifestFiles: baseManifest.files?.length || 0,
      fileIds: baseManifest.files?.map(f => f.file_id),
      storeName: baseManifest.file_search_store_name
    }, '[Manifest] Loading manifest (static import)');

    // File Search Store名の決定（環境変数優先）
    const fileSearchStoreName = envStoreName || baseManifest.file_search_store_name;

    if (envStoreName) {
      logger.info({ envStoreName }, '[Manifest] Using FILE_SEARCH_STORE_NAME from environment');
    }

    if (!envQaIds || envQaIds.length === 0) {
      return {
        ...baseManifest,
        file_search_store_name: fileSearchStoreName
      };
    }

    const filteredFiles = baseManifest.files.filter(
      f => envQaIds.includes(f.file_id)
    );

    return {
      ...baseManifest,
      file_search_store_name: fileSearchStoreName,
      files: filteredFiles
    };
  } catch (error) {
    logger.error({ error }, 'Failed to load manifest');
    return { version: '1.0.0', updated_at: '', files: [] };
  }
}

/**
 * 検索結果をパース
 */
function parseSearchResults(responseText: string, manifest: Manifest): FileSearchResult[] {
  try {
    let cleanText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '');
    const jsonMatch = cleanText.match(/\[[\s\S]*\]/);
    if (!jsonMatch) {
      logger.warn('No JSON array found in response');
      return [];
    }

    const results = JSON.parse(jsonMatch[0]);
    if (!Array.isArray(results)) {
      return [];
    }

    // カテゴリーからURLへのマッピング
    const categoryToUrl: Map<string, string> = new Map();
    manifest.files.forEach((file: ManifestFile) => {
      if (file.category && file.url) {
        categoryToUrl.set(file.category, file.url);
      }
    });

    return results.map((r: any) => {
      const category = r.category || (r.source_type === 'web' ? 'トップページ' : 'Q&A');
      const url = categoryToUrl.get(category) || 'https://wmg2027.jp/';

      return {
        text: r.answer || '',
        original_question: r.original_question || r.question || '',
        display_name: r.source_type === 'web' ? '公式サイト' : 'Q&Aデータ',
        uri: url,
        source_type: (r.source_type as 'qa' | 'web') || 'qa',
        category: category,
        locale: 'ja',
        relevance: r.relevance as 'high' | 'medium' | 'low' | undefined
      };
    });
  } catch (error) {
    logger.error({ error }, 'Failed to parse search results');
    return [];
  }
}

