      display_name: '公式サイト案内',
      uri: 'https://wmg2027.jp/',
      source_type: 'web',
      locale: 'ja'
    }
  ];
}

/**
 * Gemini APIキーを取得
 */
function getGeminiApiKey(): string | undefined {
  return process.env.GEMINI_API_KEY || process.env.GOOGLE_GENERATIVE_AI_API_KEY;
}

/**
 * モデルIDを取得
 */
function getGenerativeModelId(): string {
  const envId = process.env.GEMINI_MODEL_ID;
  if (envId) {
    return envId.replace(/^models\//, '');
  }
  return 'gemini-2.5-flash';
}
